const body = $json.body || $json;
const email = body.email_text || body.email || '';
if (!email || email.trim().length < 5) {
  throw new Error('email_text is required.');
}
return [{ json: { email_text: email, agent_results: {}, provider_trace: {} } }];

function getBase(nodeName) {
  try {
    return $items(nodeName)?.[0]?.json || {};
  } catch (error) {
    return {};
  }
}

function extractJson(content) {
  if (!content) return null;
  const raw = String(content).replace(/^\s*```json\s*/i, '').replace(/```\s*$/i, '').trim();
  try {
    return JSON.parse(raw);
  } catch (error) {
    const match = raw.match(/\{[\s\S]*\}/);
    if (!match) return null;
    try {
      return JSON.parse(match[0]);
    } catch (inner) {
      return null;
    }
  }
}

const base = getBase('Prepare Input');
const email = base.email_text || '';
const lower = email.toLowerCase();
const isComplaint = ['complaint', 'delayed', 'delay', 'damaged', 'wrong', 'issue', 'problem', 'urgent', 'replacement'].some((word) => lower.includes(word));
const fallback = {
  agent_name: 'Email Classification Agent',
  design_pattern: 'ReAct',
  category: isComplaint ? 'Client Complaint' : 'General Business Email',
  priority: lower.includes('urgent') || lower.includes('today') ? 'High' : 'Medium',
  sentiment: isComplaint ? 'Negative' : 'Neutral',
  action_required: true,
  reasoning: 'Groq HTTP Request node failed or returned no completion; safe structured fallback used.',
  provider_used: 'fallback'
};

const content = $json?.choices?.[0]?.message?.content;
const parsed = extractJson(content);
const provider = content ? 'groq' : 'fallback';
const classification = provider === 'groq'
  ? { ...fallback, ...parsed, provider_used: 'groq' }
  : fallback;

return [{
  json: {
    ...base,
    agent_results: {
      ...(base.agent_results || {}),
      classification_agent: classification
    },
    provider_trace: {
      ...(base.provider_trace || {}),
      classification_agent: provider
    }
  }
}];

