const base = getBase('Parse Response Result');
const email = base.email_text || '';
const fallback = {
  agent_name: 'Task and Follow-up Agent',
  design_pattern: 'Reflection',
  tasks: [
    {
      task: 'Review the shipment issue and arrange replacement',
      deadline: email.toLowerCase().includes('today') ? 'Today' : 'Within 1 business day',
      suggested_owner: 'Operations Team'
    }
  ],
  follow_up_recommendation: 'Follow up with the customer today and confirm replacement timing.',
  reflection: 'Groq HTTP Request node failed or returned no completion; safe structured fallback used.',
  provider_used: 'fallback'
};

const content = $json?.choices?.[0]?.message?.content;
const parsed = extractJson(content);
const provider = content ? 'groq' : 'fallback';
const task = provider === 'groq'
  ? { ...fallback, ...parsed, provider_used: 'groq' }
  : fallback;
if (!Array.isArray(task.tasks) || task.tasks.length === 0) task.tasks = fallback.tasks;

return [{
  json: {
    ...base,
    agent_results: {
      ...(base.agent_results || {}),
      task_followup_agent: task
    },
    provider_trace: {
      ...(base.provider_trace || {}),
      task_followup_agent: provider
    }
  }
}];

const classification = $json.agent_results.classification_agent || {};
const response = $json.agent_results.response_agent || {};
const task = $json.agent_results.task_followup_agent || {};
const trace = $json.provider_trace || {};
const providers = [trace.classification_agent, trace.response_agent, trace.task_followup_agent];
const providerUsed = providers.length === 3 && providers.every((provider) => provider === 'groq') ? 'groq' : 'fallback';
const owner = task.tasks?.[0]?.suggested_owner || 'Operations Team';
const followUp = (task.follow_up_recommendation || 'Follow up as needed.').replace(/\.$/, '');

return [{
  json: {
    provider_used: providerUsed,
    provider_trace: trace,
    input_email: $json.email_text,
    classification_agent: classification,
    response_agent: response,
    task_followup_agent: task,
    final_summary: {
      provider_used: providerUsed,
      overall_priority: classification.priority || 'Medium',
      recommended_action: `Assign to ${owner} and respond using the drafted reply.`,
      final_response: `This email is classified as ${classification.category || 'General Business Email'} with ${classification.priority || 'Medium'} priority. Use the drafted response, assign the task to ${owner}, and follow this timing: ${followUp}.`
    }
  }
}];
